SELECT COUNT(*) 
FROM goals 
WHERE goal_status = 'in progress';

SELECT AVG(progress_percentage) AS average_completion_percentage
FROM goal_progress
WHERE user_id = 1;

SELECT COUNT(DISTINCT user_id) AS active_user_count
FROM users
WHERE status = 'active' AND user_id IN (SELECT user_id FROM goals);

SELECT COUNT(goal_id) AS total_goals
FROM goals
WHERE creator_id IN (SELECT user_id FROM users WHERE role = 'admin');

SELECT COUNT(gp.goal_id) AS total_completed_goals
FROM goal_progress gp
WHERE gp.progress_status = 'completed';
